body.script:
(function(){
  const cv = document.getElementById('c');
  const W = 1000, H = 560;
  const dpr = Math.min(window.devicePixelRatio || 1, 2);
  cv.width = W * dpr;
  cv.height = H * dpr;
  const ctx = cv.getContext('2d');
  ctx.scale(dpr, dpr);

  const dark = matchMedia('(prefers-color-scheme:dark)').matches;
  ctx.fillStyle = dark ? '#1c1c1a' : '#ffffff';
  ctx.fillRect(0, 0, W, H);

  const PEAKS = [
    { cx: 0.18, cy: 0.42, a: 1.1, sx: 0.21, sy: 0.17 },
    { cx: 0.52, cy: 0.22, a: 2.2, sx: 0.32, sy: 0.26 },
    { cx: 0.80, cy: 0.62, a: 1.6, sx: 0.26, sy: 0.21 },
    { cx: 0.32, cy: 0.74, a: 0.9, sx: 0.19, sy: 0.15 },
    { cx: 0.90, cy: 0.18, a: 0.7, sx: 0.14, sy: 0.11 },
  ];

  function field(x, y) {
    let v = 0;
    for (const p of PEAKS) {
      const dx = (x - p.cx) / p.sx;
      const dy = (y - p.cy) / p.sy;
      v += p.a * Math.exp(-(dx * dx + dy * dy) * 0.5);
    }
    return v;
  }

  const COLS = 420, ROWS = 236;
  const g = new Float32Array((COLS + 1) * (ROWS + 1));
  let lo = Infinity, hi = -Infinity;

  for (let j = 0; j <= ROWS; j++) {
    for (let i = 0; i <= COLS; i++) {
      const v = field(i / COLS, j / ROWS);
      g[j * (COLS + 1) + i] = v;
      if (v < lo) lo = v;
      if (v > hi) hi = v;
    }
  }

  function lerp(a, b, t) { return a + t * (b - a); }
  function ei(va, vb, lv) {
    const d = vb - va;
    return Math.abs(d) < 1e-12 ? 0.5 : Math.max(0, Math.min(1, (lv - va) / d));
  }

  ctx.strokeStyle = dark ? 'rgba(210,205,190,0.60)' : 'rgba(35,35,30,0.52)';
  ctx.lineWidth = 0.55;
  ctx.lineCap = 'round';

  const LEVELS = 38;

  for (let l = 1; l < LEVELS; l++) {
    const lv = lo + (l / LEVELS) * (hi - lo);
    ctx.beginPath();

    for (let j = 0; j < ROWS; j++) {
      for (let i = 0; i < COLS; i++) {
        const v00 = g[j * (COLS + 1) + i];
        const v10 = g[j * (COLS + 1) + i + 1];
        const v11 = g[(j + 1) * (COLS + 1) + i + 1];
        const v01 = g[(j + 1) * (COLS + 1) + i];
        const code = (v00 > lv ? 8 : 0) | (v10 > lv ? 4 : 0) | (v11 > lv ? 2 : 0) | (v01 > lv ? 1 : 0);
        if (code === 0 || code === 15) continue;

        const x0 = i / COLS * W, y0 = j / ROWS * H;
        const x1 = (i + 1) / COLS * W, y1 = (j + 1) / ROWS * H;

        const T = [lerp(x0, x1, ei(v00, v10, lv)), y0];
        const R = [x1, lerp(y0, y1, ei(v10, v11, lv))];
        const B = [lerp(x0, x1, ei(v01, v11, lv)), y1];
        const L = [x0, lerp(y0, y1, ei(v00, v01, lv))];

        let s;
        switch (code) {
          case 1:  s = [[L, B]]; break;
          case 2:  s = [[B, R]]; break;
          case 3:  s = [[L, R]]; break;
          case 4:  s = [[T, R]]; break;
          case 5:  s = [[T, R], [L, B]]; break;
          case 6:  s = [[T, B]]; break;
          case 7:  s = [[T, L]]; break;
          case 8:  s = [[T, L]]; break;
          case 9:  s = [[T, B]]; break;
          case 10: s = [[T, L], [B, R]]; break;
          case 11: s = [[T, R]]; break;
          case 12: s = [[L, R]]; break;
          case 13: s = [[B, R]]; break;
          case 14: s = [[L, B]]; break;
          default: s = [];
        }

        for (const [p, q] of s) {
          ctx.moveTo(p[0], p[1]);
          ctx.lineTo(q[0], q[1]);
        }
      }
    }
    ctx.stroke();
  }
})();
